    17	//! Transforms a captured `Block` into a standalone async `Function` plus a
    18	//! corresponding call expression.
    19	//!
    20	//! This pass analyzes symbol accesses inside the block, determines which
    21	//! variables must become parameters, and synthesizes the necessary `Input`s
    22	//! and call-site arguments. Tuple and tuple-field accesses are normalized so
    23	//! that each accessed element becomes a unique parameter, with full-tuple
    24	//! reconstruction when needed.
    25	//!
    26	//! The original block is then reconstructed with all symbol references
    27	//! replaced by these synthesized parameters. The result is a function
    28	//! that encapsulates the block's logic and a call expression that invokes it.
    29	//!
    30	//! # Example
    31	//! ```leo
    32	//! // Original block
    33	//! let a: i32 = 1;
    34	//! let b: i32 = 2;
    35	//! let c: (i32, i32) = (3, 4);
    36	//! {
    37	//!     let x = a + b;
    38	//!     let y = c.0 + c.1;
    39	//!     ..
    40	//! }
    41	//!
    42	//! // Rewritten as a function + call expression (assume `variant` is `AsyncFunction` here)
    43	//! async function generated_async(a: i32, b: i32, "c.0": i32, "c.1": i32) {
    44	//!     let x = a + b;
    45	//!     let y = "c.0" + "c.1";
    46	//!     ..
    47	//! }
    48	//!
    49	//! // Call
    50	//! generated_async(a, b, c.0, c.1);
    51	//! ```
    52	
    53	use crate::{CompilerState, Replacer, SymbolAccessCollector};
    54	
    55	use leo_ast::{
    56	    AstReconstructor,
    57	    AstVisitor,
    58	    Block,
    59	    CallExpression,
    60	    Expression,
    61	    Function,
    62	    Identifier,
    63	    Input,
    64	    Location,
    65	    Node,
    66	    Path,
    67	    TupleAccess,
    68	    TupleExpression,
    69	    TupleType,
    70	    Type,
    71	    Variant,
    72	};
    73	use leo_span::{Span, Symbol};
    74	
    75	use indexmap::IndexMap;
    76	
    77	pub struct BlockToFunctionRewriter<'a> {
    78	    state: &'a mut CompilerState,
    79	    current_program: Symbol,
    80	}
    81	
    82	impl<'a> BlockToFunctionRewriter<'a> {
    83	    pub fn new(state: &'a mut CompilerState, current_program: Symbol) -> Self {
    84	        Self { state, current_program }
    85	    }
    86	}
    87	
    88	impl BlockToFunctionRewriter<'_> {
    89	    pub fn rewrite_block(
    90	        &mut self,
    91	        input: &Block,
    92	        function_name: Symbol,
    93	        function_variant: Variant,
    94	    ) -> (Function, Expression) {
    95	        // Collect all symbol accesses in the block.
    96	        let mut access_collector = SymbolAccessCollector::new(self.state);
    97	        access_collector.visit_block(input);
    98	
    99	        // Stores mapping from accessed symbol (and optional index) to the expression used in replacement.
   100	        let mut replacements: IndexMap<(Symbol, Option<usize>), Expression> = IndexMap::new();
   101	
   102	        // Helper to create a fresh `Identifier`.
   103	        let make_identifier = |slf: &mut Self, symbol: Symbol| Identifier {
   104	            name: symbol,
   105	            span: Span::default(),
   106	            id: slf.state.node_builder.next_id(),
   107	        };
   108	
   109	        // Generates a set of `Input`s and corresponding call-site `Expression`s for a given symbol access.
   110	        //
   111	        // This function handles both:
   112	        // - Direct variable accesses (e.g., `foo`)
   113	        // - Tuple element accesses (e.g., `foo.0`)
   114	        //
   115	        // For tuple accesses:
   116	        // - If a single element (e.g. `foo.0`) is accessed, it generates a synthetic input like `"foo.0"`.
   117	        // - If the whole tuple (e.g. `foo`) is accessed, it ensures all elements are covered by:
   118	        //     - Reusing existing inputs from `replacements` if already generated via prior field access.
   119	        //     - Creating new inputs and arguments for any missing elements.
   120	        // - The entire tuple is reconstructed in `replacements` using the individual elements as a `TupleExpression`.
   121	        //
   122	        // This function also ensures deduplication by consulting the `replacements` map:
   123	        // - If a given `(symbol, index)` has already been processed, no duplicate input or argument is generated.
   124	        // - This prevents repeated parameters for accesses like both `foo` and `foo.0`.
   125	        //
   126	        // # Parameters
   127	        // - `symbol`: The symbol being accessed.
   128	        // - `var_type`: The type of the symbol (may be a tuple or base type).
   129	        // - `index_opt`: `Some(index)` for a tuple field (e.g., `.0`), or `None` for full-variable access.
   130	        //
   131	        // # Returns
   132	        // A `Vec<(Input, Expression)>`, where:
   133	        // - `Input` is a parameter for the generated function.
   134	        // - `Expression` is the call-site argument expression used to invoke that parameter.
   135	        let mut make_inputs_and_arguments =
   136	            |slf: &mut Self, symbol: Symbol, var_type: &Type, index_opt: Option<usize>| -> Vec<(Input, Expression)> {
   137	                if replacements.contains_key(&(symbol, index_opt)) {
   138	                    return vec![]; // No new input needed; argument already exists
   139	                }
   140	
   141	                match index_opt {
   142	                    Some(index) => {
   143	                        let Type::Tuple(TupleType { elements }) = var_type else {
   144	                            panic!("Expected tuple type when accessing tuple field: {symbol}.{index}");
   145	                        };
   146	
   147	                        let synthetic_name = format!("\"{symbol}.{index}\"");
   148	                        let synthetic_symbol = Symbol::intern(&synthetic_name);
   149	                        let identifier = make_identifier(slf, synthetic_symbol);
   150	
   151	                        let input = Input {
   152	                            identifier,
   153	                            mode: leo_ast::Mode::None,
   154	                            type_: elements[index].clone(),
   155	                            span: Span::default(),
   156	                            id: slf.state.node_builder.next_id(),
   157	                        };
   158	
   159	                        replacements.insert((symbol, Some(index)), Path::from(identifier).to_local().into());
   160	
   161	                        vec![(
   162	                            input,
   163	                            TupleAccess {
   164	                                tuple: Path::from(make_identifier(slf, symbol)).to_local().into(),
   165	                                index: index.into(),
   166	                                span: Span::default(),
   167	                                id: slf.state.node_builder.next_id(),
   168	                            }
   169	                            .into(),
   170	                        )]
   171	                    }
   172	
   173	                    None => match var_type {
   174	                        Type::Tuple(TupleType { elements }) => {
   175	                            let mut inputs_and_arguments = Vec::with_capacity(elements.len());
   176	                            let mut tuple_elements = Vec::with_capacity(elements.len());
   177	
   178	                            for (i, element_type) in elements.iter().enumerate() {
   179	                                let key = (symbol, Some(i));
   180	
   181	                                // Skip if this field is already handled
   182	                                if let Some(existing_expr) = replacements.get(&key) {
   183	                                    tuple_elements.push(existing_expr.clone());
   184	                                    continue;
   185	                                }
   186	
   187	                                // Otherwise, synthesize identifier and input
   188	                                let synthetic_name = format!("\"{symbol}.{i}\"");
   189	                                let synthetic_symbol = Symbol::intern(&synthetic_name);
   190	                                let identifier = make_identifier(slf, synthetic_symbol);
   191	
   192	                                let input = Input {
   193	                                    identifier,
   194	                                    mode: leo_ast::Mode::None,
   195	                                    type_: element_type.clone(),
   196	                                    span: Span::default(),
   197	                                    id: slf.state.node_builder.next_id(),
   198	                                };
   199	
   200	                                let expr: Expression = Path::from(identifier).to_local().into();
   201	
   202	                                replacements.insert(key, expr.clone());
   203	                                tuple_elements.push(expr.clone());
   204	                                inputs_and_arguments.push((
   205	                                    input,
   206	                                    TupleAccess {
   207	                                        tuple: Path::from(make_identifier(slf, symbol)).to_local().into(),
   208	                                        index: i.into(),
   209	                                        span: Span::default(),
   210	                                        id: slf.state.node_builder.next_id(),
   211	                                    }
   212	                                    .into(),
   213	                                ));
   214	                            }
   215	
   216	                            // Now insert the full tuple (even if all fields were already there).
   217	                            replacements.insert(
   218	                                (symbol, None),
   219	                                Expression::Tuple(TupleExpression {
   220	                                    elements: tuple_elements,
   221	                                    span: Span::default(),
   222	                                    id: slf.state.node_builder.next_id(),
   223	                                }),
   224	                            );
   225	
   226	                            inputs_and_arguments
   227	                        }
   228	
   229	                        _ => {
   230	                            let identifier = make_identifier(slf, symbol);
   231	                            let input = Input {
   232	                                identifier,
   233	                                mode: leo_ast::Mode::None,
   234	                                type_: var_type.clone(),
   235	                                span: Span::default(),
   236	                                id: slf.state.node_builder.next_id(),
   237	                            };
   238	
   239	                            replacements.insert((symbol, None), Path::from(identifier).to_local().into());
   240	
   241	                            let argument = Path::from(make_identifier(slf, symbol)).to_local().into();
   242	                            vec![(input, argument)]
   243	                        }
   244	                    },
   245	                }
   246	            };
   247	
   248	        // Resolve symbol accesses into inputs and call arguments.
   249	        let (inputs, arguments): (Vec<_>, Vec<_>) = access_collector
   250	            .symbol_accesses
   251	            .iter()
   252	            .filter_map(|(path, index)| {
   253	                // Skip globals and variables that are local to this block or to one of its children.
   254	
   255	                // Skip globals.
   256	                if path.is_global() {
   257	                    return None;
   258	                }
   259	
   260	                // Skip variables that are local to this block or to one of its children.
   261	                let local_var_name = path.expect_local_symbol(); // Not global, so must be local 
   262	                if self.state.symbol_table.is_local_to_or_in_child_scope(input.id(), local_var_name) {
   263	                    return None;
   264	                }
   265	
   266	                // All other variables become parameters to the function being built.
   267	                let var = self.state.symbol_table.lookup_local(local_var_name)?;
   268	                Some(make_inputs_and_arguments(self, local_var_name, &var.type_.expect("must be known by now"), *index))
   269	            })
   270	            .flatten()
   271	            .unzip();
   272	
   273	        // Replacement logic used to patch the block.
   274	        let replace_expr = |expr: &Expression| -> Expression {
   275	            match expr {
   276	                Expression::Path(path) => {
   277	                    replacements.get(&(path.identifier().name, None)).cloned().unwrap_or_else(|| expr.clone())
   278	                }
   279	
   280	                Expression::TupleAccess(ta) => {
   281	                    if let Expression::Path(path) = &ta.tuple {
   282	                        replacements
   283	                            .get(&(path.identifier().name, Some(ta.index.value())))
   284	                            .cloned()
   285	                            .unwrap_or_else(|| expr.clone())
   286	                    } else {
   287	                        expr.clone()
   288	                    }
   289	                }
   290	
   291	                _ => expr.clone(),
   292	            }
   293	        };
   294	
   295	        // Reconstruct the block with replaced references.
   296	        let mut replacer = Replacer::new(replace_expr, true /* refresh IDs */, self.state);
   297	        let new_block = replacer.reconstruct_block(input.clone()).0;
   298	
   299	        // Define the new function.
   300	        let function = Function {
   301	            annotations: vec![],
   302	            variant: function_variant,
   303	            identifier: make_identifier(self, function_name),
   304	            const_parameters: vec![],
   305	            input: inputs,
   306	            output: vec![],          // No returns supported yet.
   307	            output_type: Type::Unit, // No returns supported yet.
   308	            block: new_block,
   309	            span: input.span,
   310	            id: self.state.node_builder.next_id(),
   311	        };
   312	
   313	        // Create the call expression to invoke the function.
   314	        let call_to_function = CallExpression {
   315	            function: Path::from(make_identifier(self, function_name))
   316	                .to_global(Location::new(self.current_program, vec![function_name])),
   317	            const_arguments: vec![],
   318	            arguments,
   319	            span: input.span,
   320	            id: self.state.node_builder.next_id(),
   321	        };
   322	
   323	        (function, call_to_function.into())
   324	    }
   325	}
   326

