    17	use super::ProcessingAsyncVisitor;
    18	use crate::BlockToFunctionRewriter;
    19	use leo_ast::{AstReconstructor, AsyncExpression, Block, Expression, IterationStatement, Node, Statement, Variant};
    20	
    21	impl AstReconstructor for ProcessingAsyncVisitor<'_> {
    22	    type AdditionalInput = ();
    23	    type AdditionalOutput = ();
    24	
    25	    /// Transforms an `AsyncExpression` into a standalone async `Function` and returns
    26	    /// a call to this function. This process:
    27	    fn reconstruct_async(&mut self, input: AsyncExpression, _additional: &()) -> (Expression, Self::AdditionalOutput) {
    28	        // Generate a unique name for the async function.
    29	        let finalize_fn_name = self.state.assigner.unique_symbol(self.current_function, "$");
    30	
    31	        // Convert the block into a function and a function call.
    32	        let mut block_to_function_rewriter = BlockToFunctionRewriter::new(self.state, self.current_program);
    33	        let (function, call_to_finalize) =
    34	            block_to_function_rewriter.rewrite_block(&input.block, finalize_fn_name, Variant::Finalize);
    35	
    36	        // Ensure we're not trying to capture too many variables.
    37	        if function.input.len() > self.max_inputs {
    38	            self.state.handler.emit_err(leo_errors::StaticAnalyzerError::final_block_capturing_too_many_vars(
    39	                function.input.len(),
    40	                self.max_inputs,
    41	                input.span,
    42	            ));
    43	        }
    44	
    45	        // Register the generated function
    46	        self.new_async_functions.push((finalize_fn_name, function));
    47	
    48	        self.modified = true;
    49	
    50	        (call_to_finalize, ())
    51	    }
    52	
    53	    fn reconstruct_block(&mut self, input: Block) -> (Block, Self::AdditionalOutput) {
    54	        self.in_scope(input.id(), |slf| {
    55	            (
    56	                Block {
    57	                    statements: input.statements.into_iter().map(|s| slf.reconstruct_statement(s).0).collect(),
    58	                    span: input.span,
    59	                    id: input.id,
    60	                },
    61	                Default::default(),
    62	            )
    63	        })
    64	    }
    65	
    66	    fn reconstruct_iteration(&mut self, input: IterationStatement) -> (Statement, Self::AdditionalOutput) {
    67	        self.in_scope(input.id(), |slf| {
    68	            (
    69	                IterationStatement {
    70	                    type_: input.type_.map(|ty| slf.reconstruct_type(ty).0),
    71	                    start: slf.reconstruct_expression(input.start, &()).0,
    72	                    stop: slf.reconstruct_expression(input.stop, &()).0,
    73	                    block: slf.reconstruct_block(input.block).0,
    74	                    ..input
    75	                }
    76	                .into(),
    77	                Default::default(),
    78	            )
    79	        })
    80	    }
    81	}
