    17	//! Collects all symbol accesses within an async block,
    18	//! including both direct variable identifiers (`x`) and tuple field accesses (`x.0`, `x.1`, etc.).
    19	//! Each access is recorded as a pair: (Symbol, Option<usize>).
    20	//! - `None` means a direct variable access.
    21	//! - `Some(index)` means a tuple field access.
    22	
    23	use crate::CompilerState;
    24	
    25	use leo_ast::{AstVisitor, Expression, Node as _, Path, ProgramVisitor, TupleAccess, Type};
    26	
    27	use indexmap::IndexSet;
    28	
    29	pub struct SymbolAccessCollector<'a> {
    30	    state: &'a CompilerState,
    31	    pub symbol_accesses: IndexSet<(Path, Option<usize>)>,
    32	}
    33	
    34	impl<'a> SymbolAccessCollector<'a> {
    35	    pub fn new(state: &'a mut CompilerState) -> Self {
    36	        Self { state, symbol_accesses: IndexSet::new() }
    37	    }
    38	}
    39	
    40	impl AstVisitor for SymbolAccessCollector<'_> {
    41	    type AdditionalInput = ();
    42	    type Output = ();
    43	
    44	    fn visit_path(&mut self, input: &Path, _: &Self::AdditionalInput) -> Self::Output {
    45	        self.symbol_accesses.insert((input.clone(), None));
    46	    }
    47	
    48	    fn visit_tuple_access(&mut self, input: &TupleAccess, _: &Self::AdditionalInput) -> Self::Output {
    49	        // Here we assume that we can't have nested tuples which is currently guaranteed by type
    50	        // checking. This may change in the future.
    51	        if let Expression::Path(path) = &input.tuple {
    52	            // Futures aren't accessed by field; treat the whole thing as a direct variable
    53	            if let Some(Type::Future(_)) = self.state.type_table.get(&input.tuple.id()) {
    54	                self.symbol_accesses.insert((path.clone(), None));
    55	            } else {
    56	                self.symbol_accesses.insert((path.clone(), Some(input.index.value())));
    57	            }
    58	        } else {
    59	            self.visit_expression(&input.tuple, &());
    60	        }
    61	    }
    62	}
    63	
    64	impl ProgramVisitor for SymbolAccessCollector<'_> {}
